import { useNavigate, Link } from 'react-router-dom';
import API from '../api/axios';
import React, { useState } from 'react';

const RegisterPage = () => {
  const [form, setForm] = useState({ name: '', email: '', password: '' });
  const navigate = useNavigate();
  // 1. Setup State for all form fields
  const [formData, setFormData] = useState({
    name: '',
    email: '',
    dob: '',
    level: '',
    password: '',
    confirmPassword: '',
    terms: false
  });

  // 2. Setup State for error messages
  const [errors, setErrors] = useState({});

  // 3. Handle input changes dynamically
  const handleChange = (e) => setForm({ ...form, [e.target.name]: e.target.value });
  const { name, value, type, checked } = e.target;
    
    // If it's a checkbox, we need the 'checked' value instead of 'value'
    const inputValue = type === 'checkbox' ? checked : value;

    setFormData({
      ...formData,
      [name]: inputValue
    });

    // Clear the error for this field as the user types/selects
    setErrors({
      ...errors,
      [name]: ''
    });

  // 4. Handle form submission and validation
  const handleSubmit = async (e) => {
    e.preventDefault();
    try {
const { data } = await API.post('/auth/register', form);
localStorage.setItem('token', data.token);
navigate('/home');
} catch (err) {
setError(err.response?.data?.message || 'Registration failed.');
}

    let isValid = true;
    let newErrors = {};

    // Name Validation
    if (formData.name.trim() === "") {
      newErrors.name = "Name is required";
      isValid = false;
    }
    
    // Email Validation
    if (!/^[^@]+@[^@]+\.[^@]+$/.test(formData.email)) {
      newErrors.email = "Valid email required";
      isValid = false;
    }

    // Age Validation (< 18 check)
    if (!formData.dob) {
      newErrors.dob = "Date of birth required";
      isValid = false;
    } else {
      const dobDate = new Date(formData.dob);
      const today = new Date();
      let age = today.getFullYear() - dobDate.getFullYear();
      const m = today.getMonth() - dobDate.getMonth();
      
      // Adjust age if birthday hasn't happened yet this year
      if (m < 0 || (m === 0 && today.getDate() < dobDate.getDate())) {
        age--;
      }

      if (age < 18) {
        newErrors.dob = "You must be at least 18 years old to register.";
        isValid = false;
      }
    }

    // Password Validation
    if (formData.password.length < 8) {
      newErrors.password = "Password must be 8+ chars";
      isValid = false;
    }
    if (formData.password !== formData.confirmPassword || formData.confirmPassword === "") {
      newErrors.confirmPassword = "Passwords do not match";
      isValid = false;
    }

    // Radio Button Validation
    if (!formData.level) {
      newErrors.level = "Select an experience level";
      isValid = false;
    }

    // Checkbox Validation
    if (!formData.terms) {
      newErrors.terms = "You must agree to terms";
      isValid = false;
    }

    setErrors(newErrors);

    if (isValid) {
      alert("Registration Successful! (Simulated)");
      // Optional: Reset form
      // setFormData({ name: '', email: '', dob: '', level: '', password: '', confirmPassword: '', terms: false });
    }
  };

  return (
    <main>
      <section>
        <h2>Create Account</h2>
        <div className="form-container">
          <form onSubmit={handleSubmit}>
            
            <label htmlFor="name">Full Name</label>
            <input type="text" id="rName" name="name" value={formData.name} onChange={handleChange} />
            {errors.name && <span className="error">{errors.name}</span>}

            <label htmlFor="email">Email Address</label>
            <input type="email" id="rEmail" name="email" value={formData.email} onChange={handleChange} />
            {errors.email && <span className="error">{errors.email}</span>}

            <label htmlFor="dob">Date of Birth</label>
            <input type="date" id="rDob" name="dob" value={formData.dob} onChange={handleChange} />
            {errors.dob && <span className="error">{errors.dob}</span>}

            <label>Experience Level</label>
            <div className="radio-group">
              <input type="radio" id="lvl1" name="level" value="Newbie" checked={formData.level === "Newbie"} onChange={handleChange} />
              <label htmlFor="lvl1" className="radio-label">Newbie</label>
              
              <input type="radio" id="lvl2" name="level" value="Gamer" checked={formData.level === "Gamer"} onChange={handleChange} />
              <label htmlFor="lvl2" className="radio-label">Gamer</label>
              
              <input type="radio" id="lvl3" name="level" value="Pro" checked={formData.level === "Pro"} onChange={handleChange} />
              <label htmlFor="lvl3" className="radio-label">Pro</label>
            </div>
            {errors.level && <span className="error">{errors.level}</span>}

            <label htmlFor="password">Password</label>
            <input type="password" id="rPass" name="password" value={formData.password} onChange={handleChange} />
            {errors.password && <span className="error">{errors.password}</span>}

            <label htmlFor="confirmPassword">Confirm Password</label>
            <input type="password" id="rConfirmPass" name="confirmPassword" value={formData.confirmPassword} onChange={handleChange} />
            {errors.confirmPassword && <span className="error">{errors.confirmPassword}</span>}

            <label className="checkbox-container">
              <input type="checkbox" id="terms" name="terms" checked={formData.terms} onChange={handleChange} />
              <span className="checkmark"></span>
              I agree to the Terms and Conditions
            </label>
            {errors.terms && <span className="error">{errors.terms}</span>}

            <button type="submit" className="quiz-btn">Register Now</button>
          </form>
        </div>
        <div className='register-page'>
          <h2>Create an Account</h2>
            {error && <p className='error-msg'>{error}</p>}
        <form onSubmit={handleSubmit}>
          <input name='name' placeholder='Full name' value={form.name}
           onChange={handleChange} required />
          <input name='email' type='email' placeholder='Email' value={form.email}
            onChange={handleChange} required />
          <input name='password' type='password' placeholder='Password (min 6 chars)' value={form.password} onChange={handleChange} required minLength={6} />
          <button type='submit'>Register</button>
        </form>
    <p>Already have an account? <Link to='/login'>Login</Link></p>
        </div>
      </section>
    </main>
  );
};

export default RegisterPage;
